type account struct {
	ID       string
	Balance  int64
	Currency string
}

type transactionServer struct {
	bankingv1.UnimplementedTransactionServiceServer

	mu          sync.RWMutex
	accounts    map[string]*account
	txSeq       int64
}

func newTransactionServer() *transactionServer {
	return &transactionServer{
		accounts: map[string]*account{
			"acct_1": {ID: "acct_1", Balance: 100000, Currency: "USD"},
			"acct_2": {ID: "acct_2", Balance: 50000, Currency: "USD"},
			"acct_3": {ID: "acct_3", Balance: 25000, Currency: "USD"},
		},
	}
}

func (s *transactionServer) CreateTransaction(ctx context.Context, req *bankingv1.CreateTransactionRequest) (*bankingv1.CreateTransactionResponse, error) {
	if req.GetFromAccountId() == "" || req.GetToAccountId() == "" {
		return nil, errors.New("from_account_id and to_account_id are required")
	}
	if req.GetFromAccountId() == req.GetToAccountId() {
		return nil, errors.New("from_account_id and to_account_id must be different")
	}
	if req.GetAmount() <= 0 {
		return nil, errors.New("amount must be greater than zero")
	}
	if req.GetCurrency() == "" {
		return nil, errors.New("currency is required")
	}

	s.mu.Lock()
	defer s.mu.Unlock()

	from, ok := s.accounts[req.GetFromAccountId()]
	if !ok {
		return nil, errors.New("source account not found")
	}
	to, ok := s.accounts[req.GetToAccountId()]
	if !ok {
		return nil, errors.New("destination account not found")
	}
	if from.Currency != req.GetCurrency() || to.Currency != req.GetCurrency() {
		return nil, errors.New("currency mismatch")
	}
	if from.Balance < req.GetAmount() {
		return nil, errors.New("insufficient funds")
	}

	from.Balance -= req.GetAmount()
	to.Balance += req.GetAmount()
	s.txSeq++

	return &bankingv1.CreateTransactionResponse{
		TransactionId: generateTransactionID(s.txSeq),
		Status:        "COMPLETED",
		FromBalance:   from.Balance,
		ToBalance:     to.Balance,
	}, nil
}

func (s *transactionServer) GetBalance(ctx context.Context, req *bankingv1.GetBalanceRequest) (*bankingv1.GetBalanceResponse, error) {
	if req.GetAccountId() == "" {
		return nil, errors.New("account_id is required")
	}

	s.mu.RLock()
	defer s.mu.RUnlock()

	acct, ok := s.accounts[req.GetAccountId()]
	if !ok {
		return nil, errors.New("account not found")
	}

	return &bankingv1.GetBalanceResponse{
		AccountId: acct.ID,
		Balance:   acct.Balance,
		Currency:  acct.Currency,
	}, nil
}

func generateTransactionID(seq int64) string {
	return "tx_" + time.Now().UTC().Format("20060102150405") + "_" + itoa(seq)
}

func itoa(v int64) string {
	if v == 0 {
		return "0"
	}
	var buf [20]byte
	i := len(buf)
	n := v
	for n > 0 {
		i--
		buf[i] = byte('0' + n%10)
		n /= 10
	}
	return string(buf[i:])
}

